function magazynDokumentPotwierdzLokalizacjeSkanu(documentId){const key=String(documentId),session=magazynDokumentSkanSesja(documentId);if(!session.proposedLocation)return false;session.confirmedLocation=session.proposedLocation;session.proposedLocation="";session.nextLocation="";magazynDokumentSkanLokalizacje[key]=session.confirmedLocation;magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`✅ Półka ${magazynDokumentWidocznaLokalizacja(session.confirmedLocation)} zatwierdzona. Zeskanuj produkt.`);toast(`✅ Zatwierdzono półkę ${magazynDokumentWidocznaLokalizacja(session.confirmedLocation)}`);return true;}
